const XLSX = require('xlsx');
const fs = require('fs');

// 1. 读取推广商品记录.txt
const txt = fs.readFileSync('推广商品记录.txt', 'utf8');
const rawIds = txt.split('\n').map(l => l.trim()).filter(l => /^\d{13}$/.test(l));
console.log('=== 推广商品记录.txt ===');
console.log('商品ID总数:', rawIds.length);
console.log();

// 2. 读取产品参谋（获取正确标题）
const wb1 = XLSX.readFile('Products-2026-04-18 (1).xls');
const ws1 = wb1.Sheets['产品分析'];
const data1 = XLSX.utils.sheet_to_json(ws1, {header:1});
const titleMap = {};
for(let i = 6; i < data1.length; i++) {
  const row = data1[i];
  if(row && row[0]) {
    const id = String(row[0]).trim();
    titleMap[id] = (row[1]||'').trim();
  }
}
console.log('产品参谋商品总数:', Object.keys(titleMap).length);

// 3. 读取全站推广数据（测品计划中的商品）
const wb2 = XLSX.readFile('全站推广-商品(投放时段_2026-04-07 ~ 2026-04-23).xlsx');
const ws2 = wb2.Sheets['sheet1'];
const data2 = XLSX.utils.sheet_to_json(ws2, {header:1});
const promoMap = {};
for(let i = 1; i < data2.length; i++) {
  const row = data2[i];
  if(row && row[2]) {
    const id = String(row[2]).trim();
    promoMap[id] = {
      title: row[1] || '',
      exposure: row[9] || 0,    // 曝光量
      click: row[7] || 0,       // 点击量
      ctr: row[10] || '0%',     // 点击率
      inquiry: row[11] || 0,    // 询盘量
      order: row[13] || 0,      // 订单量
      biz: row[3] || 0          // 全站商机量
    };
  }
}
console.log('测品计划商品数:', Object.keys(promoMap).length);
console.log();

// 4. 对比分析
console.log('=== 第一批38个商品ID审计报告 ===');
console.log();

// 在测品计划中的
const inPlan = rawIds.filter(id => promoMap[id]);
const notInPlan = rawIds.filter(id => !promoMap[id]);

console.log('--- 在测品计划中的商品 (' + inPlan.length + '个) ---');
inPlan.forEach(id => {
  const p = promoMap[id];
  const title = titleMap[id] || '(标题未知)';
  console.log(id, '|', (p.title||'').substring(0,40), '|', '曝光:'+p.exposure, '点击:'+p.click, 'CTR:'+p.ctr, '商机:'+p.biz);
});

console.log();
console.log('--- 未在测品计划中的商品（遗漏）(' + notInPlan.length + '个) ---');
notInPlan.forEach(id => {
  const title = titleMap[id] || '(标题未知)';
  console.log(id, '|', title.substring(0,50));
});

console.log();
console.log('=== 汇总 ===');
console.log('第一批总商品:', rawIds.length);
console.log('已在测品计划:', inPlan.length);
console.log('未在测品计划（遗漏）:', notInPlan.length);
