> 说明：本表覆盖店铺全部517个产品，含推广状态、所属计划、简要备注

---

## 一、状态总览

| 状态分类 | 数量 | 说明 |
|---------|:---:|------|
| ✅ 推广中-核心爆品 | ${allEntries.filter(e => e.status.includes('核心爆品')).length} | 日预算版，商机≥8 |
| ✅ 推广中-优质品 | ${allEntries.filter(e => e.status.includes('优质品') && !e.status.includes('核心')).length} | 日预算版，商机3-6 |
| ⚠️ 边缘观察 | ${allEntries.filter(e => e.status.includes('边缘观察')).length} | 日预算版，商机1-4，观察中 |
| 🏆 待转日预算版 | ${allEntries.filter(e => e.status.includes('待转')).length} | 智投版已达标，准备转入 |
| 📈 测试中-有潜力 | ${allEntries.filter(e => e.status.includes('有潜力')).length} | 智投版，CTR较高继续测试 |
| 🔍 测试中-数据不足 | ${allEntries.filter(e => e.status.includes('数据不足')).length} | 智投版，曝光<100 |
| 🔍 测试中-观察中 | ${allEntries.filter(e => e.status.includes('观察中') && e.plan === '智投版').length} | 智投版，数据尚浅继续观察 |
| ❌ 已淘汰 | ${allEntries.filter(e => e.status.includes('已淘汰')).length} | 两计划共已淘汰品 |
| ⬜ 未推广 | ${allEntries.filter(e => e.status === '⬜ 未推广').length} | 从未加入P4P计划 |
| ❓ 未在产品参谋中出现 | ${missingIds.length} | 有产品ID但产品参谋中查不到数据 |

`;

// 按状态分组输出
const groups = [
  { title: '✅ 推广中-核心爆品（日预算版，商机≥8，重点维持）', filter: e => e.status.includes('核心爆品') },
  { title: '✅ 推广中-优质品（日预算版，商机3-6，正常维持）', filter: e => e.status.includes('优质品') && !e.status.includes('核心') },
  { title: '⚠️ 边缘观察（日预算版，商机1-4，观察中）', filter: e => e.status.includes('边缘观察') },
  { title: '🏆 待转日预算版（智投版已达标，准备转入日预算版）', filter: e => e.status.includes('待转') },
  { title: '📈 测试中-有潜力（智投版，CTR较高，继续测试）', filter: e => e.status.includes('有潜力') },
  { title: '🔍 测试中-数据不足/观察中（智投版，曝光不足或数据尚浅）', filter: e => e.plan === '智投版' && (e.status.includes('数据不足') || e.status.includes('观察中')) },
  { title: '❌ 已淘汰', filter: e => e.status.includes('已淘汰') },
];

groups.forEach(g => {
  const items = allEntries.filter(g.filter);
  if (items.length === 0) return;
  md += `\n## ${g.title}（${items.length}个）\n\n`;
  md += `| # | 产品ID | 标题 | 橱窗 | 搜索曝光 | 询盘 | 备注 |\n`;
  md += `|---|--------|------|:---:|:-------:|:----:|------|\n`;
  items.sort((a, b) => (b.searchExp || 0) - (a.searchExp || 0)).forEach((e, i) => {
    const title = (e.title || '').substring(0, 50);
    md += `| ${i+1} | ${e.id} | ${title} | ${e.showcase} | ${e.searchExp || '-'} | ${e.inquiries || '-'} | ${e.note} |\n`;
  });
});

// 未推广产品 - 按品类分组
const untested = allEntries.filter(e => e.status === '⬜ 未推广');
md += `\n## ⬜ 未推广产品（${untested.length}个）\n\n`;
md += `> 以下产品从未加入过P4P推广计划。按产品关键词分类：\n\n`;

const catRules = [
  { name: '连体衣/Romper/Onesie', kw: /romper|onesie|连体衣|jumpsuit|baby.*suit|婴儿.*衣/i },
  { name: '儿童套装/Kids Set', kw: /(?:kids|child|boy|girl|toddler|儿童|婴幼).*set|套装/i },
  { name: '布尿裤/训练裤/纸尿裤', kw: /diaper|nappy|布尿裤|训练裤|potty|纸尿裤|training.*pants/i },
  { name: '围兜/Bibs/口水巾', kw: /bib|围兜|口水巾|burp/i },
  { name: '吸汗巾/方巾/Saliva', kw: /saliva|吸汗巾|方巾|handker|drool/i },
  { name: '睡袋/抱被/Swaddle', kw: /swaddle|睡袋|抱被|sleep.*sack/i },
  { name: '床品/盖毯/Blanket', kw: /blanket|盖毯|床品|quilt|comforter|bedding/i },
  { name: '浴巾/浴袍/Towel', kw: /towel|浴巾|浴袍|hooded.*bath/i },
  { name: '隔尿垫/尿垫', kw: /垫|changing.*pad|waterproof.*pad/i },
  { name: '枕头/定型枕', kw: /pillow|定型枕|枕头/i },
  { name: '裙装/Dress', kw: /dress|裙/i },
  { name: '保暖/睡衣/Pajama', kw: /pajama|睡衣|sleepwear|underwear|内衣|thermal/i },
  { name: '运动装/外套/Tracksuit', kw: /track|运动|外套|jacket|hoodie|coat/i },
  { name: '其他/配饰', kw: /.*/ },
];

const categorized = new Set();
catRules.forEach(cat => {
  const items = untested.filter(e => cat.kw.test(e.title) && !categorized.has(e.id));
  if (items.length === 0) return;
  items.forEach(e => categorized.add(e.id));
  md += `### ${cat.name}（${items.length}个）\n\n`;
  md += `| # | 产品ID | 标题（前50字） | 橱窗 | 搜索曝光 |\n`;
  md += `|---|--------|----------------|:---:|:-------:|\n`;
  items.sort((a, b) => (b.searchExp || 0) - (a.searchExp || 0)).forEach((e, i) => {
    const title = (e.title || '').substring(0, 50);
    md += `| ${i+1} | ${e.id} | ${title} | ${e.showcase} | ${e.searchExp || '-'} |\n`;
  });
  md += '\n';
});

// Note about 35 missing products
md += `\n---\n`;
md += `\n## ❓ 补充说明\n\n`;
md += `- **产品参谋中未出现的产品**：店铺共517个产品，但本表只有482条来自数据参谋-产品参谋的导出。\n`;
md += `  剩余35个产品在产品参谋中查不到任何数据，可能是极新产品或未收录品。\n`;
md += `- **P4P产品中完全无产品参谋数据的**：${missingIds.length>0?missingIds.join(', '):'无，所有87个P4P产品均能在产品参谋查到'}\n`;
md += `- **数据周期**：曝光/询盘等数据来自2026-04-12~2026-04-18的产品参谋周报\n`;
md += `- **建议**：未推广的 ${untested.length} 个产品可作为后续轮测的候选池\n`;

// Write file
const fs = require('fs');
fs.writeFileSync('C:\\Users\\Administrator\\Desktop\\全店产品推广状态总表.md', md, 'utf8');
console.log('文件已生成！');
console.log('总条目数:', allEntries.length);

