const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const USER_DATA_DIR = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data';
const PROFILE_DIR = 'Default';
const OUTPUT_DIR = 'C:\\Users\\Administrator\\Desktop\\P4P优化专用';

(async () => {
  console.log('启动浏览器...');
  const context = await chromium.launchPersistentContext(
    path.join(USER_DATA_DIR, PROFILE_DIR),
    {
      headless: false,
      viewport: { width: 1280, height: 800 },
      args: [
        '--disable-blink-features=AutomationControlled',
        '--no-sandbox',
      ],
    }
  );

  const page = await context.newPage();

  // Step 1: Go to Alibaba seller center
  console.log('正在访问阿里巴巴国际站卖家中心...');
  await page.goto('https://seller.alibaba.com', { waitUntil: 'networkidle', timeout: 60000 });

  // Check login state
  const currentUrl = page.url();
  console.log('当前URL:', currentUrl);

  // Take screenshot
  await page.screenshot({ path: path.join(OUTPUT_DIR, '01_seller_center.png'), fullPage: false });

  // Check if we're on login page or already logged in
  if (currentUrl.includes('login') || currentUrl.includes('sign') || currentUrl.includes('passport')) {
    console.log('需要登录，尝试导航到直通车页面可能触发跳转登录...');

    // Try going directly to the P4P page
    console.log('正在访问P4P直通车页面...');
    await page.goto('https://ad.alibaba.com/campaign/list.htm', { waitUntil: 'networkidle', timeout: 60000 });
    await page.screenshot({ path: path.join(OUTPUT_DIR, '02_p4p_page.png'), fullPage: false });

    const adUrl = page.url();
    console.log('P4P页面URL:', adUrl);

    if (adUrl.includes('login') || adUrl.includes('passport')) {
      console.log('===== 需要手动登录 =====');
      console.log('请在打开的浏览器窗口中登录您的阿里巴巴国际站账号');
      console.log('登录完成后，按 Enter 键继续...');

      // Wait for user to log in manually
      await new Promise(resolve => {
        process.stdin.once('data', () => resolve());
      });

      console.log('继续执行...');
    }
  } else {
    console.log('似乎已登录，正在前往P4P页面...');
  }

  // Step 2: Navigate to 直通车 campaign list
  console.log('正在导航到P4P直通车...');
  await page.goto('https://ad.alibaba.com/campaign/list.htm', { waitUntil: 'networkidle', timeout: 60000 });
  await page.waitForTimeout(3000);
  await page.screenshot({ path: path.join(OUTPUT_DIR, '03_campaign_list.png'), fullPage: false });
  console.log('当前页面:', page.url());

  // Try to find campaign list
  const campaigns = await page.$$('.campaign-item, .campaign-card, tr, [class*="campaign"]');
  console.log(`找到 ${campaigns.length} 个推广计划元素`);

  // Get page content for analysis
  const content = await page.content();
  fs.writeFileSync(path.join(OUTPUT_DIR, 'page_content.html'), content);
  console.log('页面已保存');

  await page.screenshot({ path: path.join(OUTPUT_DIR, '04_final.png'), fullPage: true });

  console.log('完成。请查看截图了解页面状态。');

  // Keep browser open for user to interact
  console.log('浏览器保持打开，按 Ctrl+C 关闭');
  await new Promise(() => {});
})();

