const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const USER_DATA_DIR = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data';
const PROFILE_DIR = 'Default';
const OUTPUT_DIR = 'C:\\Users\\Administrator\\Desktop\\P4P优化专用';

async function autoScroll(page) {
  await page.evaluate(async () => {
    await new Promise(resolve => {
      let totalHeight = 0;
      const distance = 300;
      const timer = setInterval(() => {
        const scrollHeight = document.body.scrollHeight;
        window.scrollBy(0, distance);
        totalHeight += distance;
        if (totalHeight >= scrollHeight) {
          clearInterval(timer);
          resolve();
        }
      }, 100);
    });
  });
}

async function extractTableData(page, selector) {
  return await page.evaluate((sel) => {
    const table = document.querySelector(sel);
    if (!table) return null;
    const rows = table.querySelectorAll('tr');
    const data = [];
    for (const row of rows) {
      const cells = row.querySelectorAll('td, th');
      if (cells.length > 0) {
        data.push(Array.from(cells).map(c => c.textContent.trim()));
      }
    }
    return data;
  }, selector);
}

(async () => {
  console.log('启动浏览器...');
  const context = await chromium.launchPersistentContext(
    path.join(USER_DATA_DIR, PROFILE_DIR),
    {
      headless: false,
      viewport: { width: 1400, height: 900 },
      args: ['--disable-blink-features=AutomationControlled', '--no-sandbox'],
    }
  );

  const page = context.pages()[0] || await context.newPage();

  // Step 1: Go to Alibaba seller center via www.alibaba.com
  console.log('[1/6] 正在访问 www.alibaba.com...');
  await page.goto('https://www.alibaba.com', { waitUntil: 'domcontentloaded', timeout: 60000 });
  await page.waitForTimeout(2000);

  // Step 2: Click 卖家中心
  console.log('[2/6] 点击卖家中心...');
  try {
    // Look for the 卖家中心 link
    const sellerCenterLinks = await page.$$('a');
    let clicked = false;
    for (const link of sellerCenterLinks) {
      const text = await link.textContent();
      if (text.trim() === '卖家中心' || text.trim() === 'Seller Center') {
        await link.click();
        clicked = true;
        console.log('已点击卖家中心');
        break;
      }
    }
    if (!clicked) {
      // Try navigating directly
      console.log('未找到卖家中心链接，直接导航');
      await page.goto('https://seller.alibaba.com', { waitUntil: 'domcontentloaded', timeout: 30000 });
    }
  } catch(e) {
    console.log('点击卖家中心失败:', e.message);
    await page.goto('https://seller.alibaba.com', { waitUntil: 'domcontentloaded', timeout: 30000 });
  }

  await page.waitForTimeout(4000);
  console.log('当前URL:', page.url());
  await page.screenshot({ path: path.join(OUTPUT_DIR, '01_seller_center.png'), fullPage: false });

  // Check if logged in
  const url = page.url();
  if (url.includes('passport') || url.includes('login') || url.includes('sign')) {
    console.log('[!] 需要登录，正在尝试登录流程...');
    // Try clicking sign in on www.alibaba.com
    await page.goto('https://www.alibaba.com', { waitUntil: 'domcontentloaded', timeout: 30000 });
    await page.waitForTimeout(2000);

    // Click 登录 button
    const loginBtns = await page.$$('a, button, span');
    for (const btn of loginBtns) {
      try {
        const text = await btn.textContent();
        if (text.trim() === '登录' || text.trim() === 'Sign In') {
          await btn.click();
          console.log('已点击登录按钮');
          break;
        }
      } catch(e) {}
    }

    await page.waitForTimeout(5000);
    await page.screenshot({ path: path.join(OUTPUT_DIR, '02_login_page.png'), fullPage: false });
    console.log('当前登录URL:', page.url());

    // Check if we're on a login page - wait for user to complete login
    if (page.url().includes('passport') || page.url().includes('login') || page.url().includes('sign')) {
      console.log('\n===== 请在打开的浏览器中手动登录 =====');
      console.log('登录后此脚本会自动继续...');

      // Wait until we navigate away from login page
      try {
        await page.waitForURL(u => !u.includes('passport') && !u.includes('login') && !u.includes('sign'), { timeout: 120000 });
        console.log('检测到登录成功！');
      } catch(e) {
        console.log('登录等待超时，继续尝试...');
      }
    }
  }

  // Now we should be in the seller center
  console.log('[3/6] 在卖家中心中查找推广/营销入口...');
  await page.waitForTimeout(3000);
  await page.screenshot({ path: path.join(OUTPUT_DIR, '03_seller_home.png'), fullPage: false });

  // Save page text to analyze structure
  const bodyText = await page.evaluate(() => document.body.innerText);
  fs.writeFileSync(path.join(OUTPUT_DIR, 'seller_text.txt'), bodyText);
  console.log('页面文本已保存');

  // Look for navigation links related to 推广/营销/广告
  const allLinks = await page.$$('a');
  let navItems = [];
  for (const link of allLinks) {
    try {
      const text = await link.textContent();
      const href = await link.getAttribute('href');
      if (text && text.length > 0 && text.length < 30) {
        navItems.push({ text: text.trim(), href: (href || '').substring(0, 100) });
      }
    } catch(e) {}
  }
  console.log('所有导航链接:');
  navItems.forEach(n => console.log(`  ${n.text} -> ${n.href}`));

  // Look for the marketing/advertising section
  const marketingRelated = navItems.filter(n =>
    n.text.includes('推广') || n.text.includes('营销') || n.text.includes('广告') ||
    n.text.includes('直通') || n.text.includes('P4P') || n.text.includes('promot') ||
    n.text.includes('market') || n.text.includes('advert') || n.text.includes('campaign')
  );
  console.log('\n营销相关链接:');
  marketingRelated.forEach(n => console.log(`  ${n.text} -> ${n.href}`));

  // Try clicking on marketing/推广 links
  if (marketingRelated.length > 0) {
    try {
      console.log(`点击 "${marketingRelated[0].text}"...`);
      await page.goto(marketingRelated[0].href.startsWith('http') ? marketingRelated[0].href : `https://seller.alibaba.com${marketingRelated[0].href}`,
        { waitUntil: 'domcontentloaded', timeout: 30000 });
      await page.waitForTimeout(3000);
      console.log('当前URL:', page.url());
      await page.screenshot({ path: path.join(OUTPUT_DIR, '04_marketing_page.png'), fullPage: false });
    } catch(e) {
      console.log('导航到营销页面失败:', e.message);
    }
  }

  // Try known P4P URLs
  console.log('\n[4/6] 尝试访问推广管理页面...');
  const p4pUrls = [
    'https://crm.seller.alibaba.com/ad/campaign/list',
    'https://crm.seller.alibaba.com/ad/',
    'https://crm.seller.alibaba.com/',
    'https://www.alibaba.com/crm/ad/campaign/list',
    'https://www.alibaba.com/ad/campaign/list',
    'https://crm.seller.alibaba.com/p4p/campaign/list',
    'https://crm.alibaba.com/',
  ];

  let p4pPage = false;
  for (const url of p4pUrls) {
    try {
      console.log(`  尝试 ${url}...`);
      await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 20000 });
      await page.waitForTimeout(2000);
      console.log(`  -> ${page.url()}`);
      if (!page.url().includes('passport') && !page.url().includes('login') && !page.url().includes('404') && !page.url().includes('error')) {
        console.log('  ✓ 成功访问!');
        p4pPage = true;
        break;
      }
    } catch(e) {
      console.log(`  ✗ ${e.message.substring(0, 60)}`);
    }
  }

  if (!p4pPage) {
    console.log('\n[!] 自动导航未找到P4P页面，请在浏览器中手动导航到直通车页面');
    console.log('完成后输入 "done" 回车');
    await page.screenshot({ path: path.join(OUTPUT_DIR, '05_stuck.png'), fullPage: false });

    await new Promise(resolve => {
      const handler = (data) => {
        const input = data.toString().trim().toLowerCase();
        if (input === 'done') {
          process.stdin.removeListener('data', handler);
          resolve();
        }
      };
      process.stdin.on('data', handler);
    });
  }

  // Now we should be on the campaign list page
  console.log('\n[5/6] 读取推广计划数据...');
  await page.waitForTimeout(3000);
  await autoScroll(page);
  await page.screenshot({ path: path.join(OUTPUT_DIR, '06_campaign_page.png'), fullPage: true });

  // Save page content for analysis
  const pageHtml = await page.content();
  fs.writeFileSync(path.join(OUTPUT_DIR, 'campaign_page.html'), pageHtml);
  const pageText = await page.evaluate(() => document.body.innerText);
  fs.writeFileSync(path.join(OUTPUT_DIR, 'campaign_text.txt'), pageText);
  console.log('页面数据已保存');

  // Try to extract any tables or data grids
  const tables = await page.$$('table');
  console.log(`找到 ${tables.length} 个表格`);
  for (let i = 0; i < tables.length; i++) {
    const data = await extractTableData(page, `table:nth-of-type(${i+1})`);
    if (data && data.length > 1) {
      console.log(`表格 ${i+1}: ${data.length} 行`);
      console.log(data.slice(0, 3).map(r => r.join(' | ')).join('\n'));
      fs.writeFileSync(path.join(OUTPUT_DIR, `table_${i+1}.json`), JSON.stringify(data, null, 2));
    }
  }

  // Try to find campaign items
  const campaignElems = await page.$$('[class*="campaign"], [class*="Campaign"], tr, [class*="row"], [class*="item"]');
  console.log(`潜在数据行元素: ${campaignElems.length}`);

  console.log('\n[6/6] 完成数据采集');
  console.log(`所有截图和页面数据保存在: ${OUTPUT_DIR}`);

  // Keep browser open for user inspection
  console.log('\n浏览器保持打开，按Ctrl+C关闭');
  await new Promise(() => {});
})();

