const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const USER_DATA_DIR = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Default';
const OUTPUT_DIR = 'C:\\Users\\Administrator\\Desktop\\P4P优化专用';

(async () => {
  console.log('启动浏览器...');
  const context = await chromium.launchPersistentContext(USER_DATA_DIR, {
    headless: false,
    viewport: { width: 1400, height: 900 },
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });

  const page = context.pages()[0] || await context.newPage();

  // Go to i.alibaba.com - the real seller workspace
  console.log('正在访问 i.alibaba.com ...');
  await page.goto('https://i.alibaba.com/index.htm', { waitUntil: 'domcontentloaded', timeout: 60000 });
  await page.waitForTimeout(5000);

  let curUrl = page.url();
  console.log('当前URL:', curUrl);

  // Check login status
  if (curUrl.includes('passport') || curUrl.includes('login') || curUrl.includes('sign')) {
    console.log('需要登录，请在打开的浏览器中手动登录...');
    await page.screenshot({ path: path.join(OUTPUT_DIR, 'login_needed.png'), fullPage: false });

    // Wait for login
    try {
      await page.waitForURL(u => !u.includes('passport') && !u.includes('login'), { timeout: 120000 });
      console.log('登录成功!');
    } catch(e) {
      console.log('登录超时，继续...');
    }
  } else {
    console.log('已登录!');
  }

  await page.waitForTimeout(3000);
  await page.screenshot({ path: path.join(OUTPUT_DIR, '01_workspace.png'), fullPage: false });

  // Save all links
  const links = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('a')).map(a => ({
      text: a.textContent.trim().substring(0, 80),
      href: a.href.substring(0, 200)
    })).filter(l => l.text.length > 0);
  });
  fs.writeFileSync(path.join(OUTPUT_DIR, 'all_links.json'), JSON.stringify(links, null, 2));

  // Find P4P/推广 related links
  const p4pLinks = links.filter(l =>
    /推广|直通|P4P|营销|广告|campaign|promot|advert|sponsored/i.test(l.text + l.href)
  );
  console.log(`\n找到 ${p4pLinks.length} 个推广相关链接:`);
  p4pLinks.forEach(l => console.log(`  [${l.text}] ${l.href.substring(0, 100)}`));

  // Look for navigation menu items commonly in i.alibaba.com
  console.log('\n所有主导航链接:');
  const navLinks = links.filter(l => l.href.includes('i.alibaba.com') || l.href.includes('crm') || l.href.includes('ad'));
  navLinks.forEach(l => console.log(`  ${l.text} -> ${l.href.substring(0, 100)}`));

  // Try known P4P URLs within i.alibaba.com
  const candidates = [
    ...p4pLinks.map(l => l.href),
    'https://crm.i.alibaba.com/',
    'https://crm.i.alibaba.com/ad/campaign/list',
    'https://alibaba.com/campaign/list',
  ].filter(Boolean);

  let found = false;
  for (const url of [...new Set(candidates)]) {
    if (url.includes('javascript') || url === '#' || url === '') continue;
    try {
      console.log(`\n尝试: ${url.substring(0, 100)}`);
      await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 20000 });
      await page.waitForTimeout(3000);
      const u = page.url();
      console.log(`  -> ${u}`);
      if (!u.includes('passport') && !u.includes('login') && !u.includes('error') && !u.includes('404')) {
        await page.screenshot({ path: path.join(OUTPUT_DIR, '02_p4p_page.png'), fullPage: false });
        found = true;
        break;
      }
    } catch(e) {
      console.log(`  ✗ ${e.message.substring(0, 60)}`);
    }
  }

  // Save final state
  const html = await page.content();
  fs.writeFileSync(path.join(OUTPUT_DIR, 'final.html'), html);
  const text = await page.evaluate(() => document.body.innerText);
  fs.writeFileSync(path.join(OUTPUT_DIR, 'final_text.txt'), text);

  console.log('\n完成! 数据保存在:', OUTPUT_DIR);
  console.log('浏览器保持打开，按Ctrl+C关闭');
  await new Promise(() => {});
})();

