const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const USER_DATA_DIR = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Default';
const OUTPUT_DIR = 'C:\\Users\\Administrator\\Desktop\\P4P优化专用';

(async () => {
  console.log('启动浏览器（使用你的Chrome配置）...');
  const context = await chromium.launchPersistentContext(USER_DATA_DIR, {
    headless: false,
    viewport: { width: 1400, height: 900 },
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });

  const page = context.pages()[0] || await context.newPage();

  // Go to Alibaba seller center (this worked before)
  console.log('正在访问卖家中心...');
  await page.goto('https://seller.alibaba.com', { waitUntil: 'domcontentloaded', timeout: 60000 });
  await page.waitForTimeout(4000);

  const curUrl = page.url();
  console.log('当前URL:', curUrl);

  // Check login
  if (curUrl.includes('passport') || curUrl.includes('login')) {
    console.log('需要登录，尝试通过主站登录...');
    await page.goto('https://www.alibaba.com', { waitUntil: 'domcontentloaded', timeout: 30000 });
    await page.waitForTimeout(2000);

    const loginLinks = await page.$$('a, button, span');
    for (const el of loginLinks) {
      try {
        const t = await el.textContent();
        if (t.trim() === '登录' || t.trim() === 'Sign In') {
          await el.click();
          break;
        }
      } catch(e) {}
    }
    await page.waitForTimeout(5000);

    console.log('请在打开的浏览器中手动登录，完成后输入 done 回车');
    await page.screenshot({ path: path.join(OUTPUT_DIR, 'login.png'), fullPage: false });

    await new Promise(resolve => {
      const h = d => { if (d.toString().trim().toLowerCase() === 'done') { process.stdin.removeListener('data', h); resolve(); } };
      process.stdin.on('data', h);
    });

    // Go back to seller center
    await page.goto('https://seller.alibaba.com', { waitUntil: 'domcontentloaded', timeout: 30000 });
    await page.waitForTimeout(3000);
  }

  console.log('已登录，保存卖家中心页面...');
  await page.screenshot({ path: path.join(OUTPUT_DIR, 'seller_home.png'), fullPage: false });

  // Save all links on page
  const links = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('a')).map(a => ({
      text: a.textContent.trim().substring(0, 60),
      href: a.href.substring(0, 120)
    })).filter(l => l.text.length > 0);
  });
  fs.writeFileSync(path.join(OUTPUT_DIR, 'seller_links.json'), JSON.stringify(links, null, 2));

  // Find marketing/p4p related links
  const promoLinks = links.filter(l =>
    /推广|直通|营销|广告|P4P|promot|campaign|advert/i.test(l.text) ||
    /推广|直通|营销|广告|promot|campaign/i.test(l.href)
  );
  console.log(`找到 ${promoLinks.length} 个推广相关链接:`);
  promoLinks.forEach(l => console.log(`  ${l.text} -> ${l.href}`));

  // Navigate to promo/manage page or try known paths
  const knownPaths = [
    '/crm/ad/campaign/list',
    '/ad/campaign/list',
    '/crm/p4p/campaign/list',
    '/promotion/campaign/list',
  ];

  let found = false;
  for (const link of promoLinks) {
    if (link.href && !link.href.includes('javascript') && link.href.length > 10) {
      try {
        console.log(`\n尝试打开: ${link.text}`);
        await page.goto(link.href, { waitUntil: 'domcontentloaded', timeout: 30000 });
        await page.waitForTimeout(3000);
        console.log('当前URL:', page.url());
        if (!page.url().includes('passport') && !page.url().includes('login')) {
          await page.screenshot({ path: path.join(OUTPUT_DIR, 'promo_page.png'), fullPage: false });
          found = true;
          break;
        }
      } catch(e) {
        console.log(`  失败: ${e.message.substring(0, 60)}`);
      }
    }
  }

  if (!found) {
    for (const p of knownPaths) {
      try {
        const url = `https://seller.alibaba.com${p}`;
        console.log(`\n尝试路径: ${url}`);
        await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 20000 });
        await page.waitForTimeout(2000);
        if (!page.url().includes('passport') && !page.url().includes('login') && !page.url().includes('404')) {
          console.log('成功!');
          await page.screenshot({ path: path.join(OUTPUT_DIR, 'promo_page.png'), fullPage: false });
          found = true;
          break;
        }
      } catch(e) {
        console.log(`  失败: ${e.message.substring(0, 60)}`);
      }
    }
  }

  // Save whatever page we end up on
  console.log('\n最终页面:', page.url());
  const html = await page.content();
  fs.writeFileSync(path.join(OUTPUT_DIR, 'final_page.html'), html);
  const text = await page.evaluate(() => document.body.innerText);
  fs.writeFileSync(path.join(OUTPUT_DIR, 'final_text.txt'), text);

  console.log('\n===== 数据已采集 =====');
  console.log(`截图和页面数据保存在: ${OUTPUT_DIR}`);
  console.log('浏览器保持打开，按Ctrl+C关闭');
  await new Promise(() => {});
})();

