const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const USER_DATA_DIR = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Default';
const OUTPUT_DIR = 'C:\\Users\\Administrator\\Desktop\\P4P优化专用';

async function savePageData(page, name) {
  const html = await page.content();
  fs.writeFileSync(path.join(OUTPUT_DIR, `${name}.html`), html);
  const text = await page.evaluate(() => document.body.innerText);
  fs.writeFileSync(path.join(OUTPUT_DIR, `${name}.txt`), text);
  await page.screenshot({ path: path.join(OUTPUT_DIR, `${name}.png`), fullPage: true });
  console.log(`  [已保存 ${name}]`);
}

(async () => {
  console.log('启动浏览器...');
  const context = await chromium.launchPersistentContext(USER_DATA_DIR, {
    headless: false,
    viewport: { width: 1400, height: 900 },
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });

  const page = context.pages()[0] || await context.newPage();

  // Go to i.alibaba.com marketing center
  console.log('[1] 访问 i.alibaba.com...');
  await page.goto('https://i.alibaba.com/ads/index.htm', { waitUntil: 'domcontentloaded', timeout: 60000 });
  await page.waitForTimeout(4000);

  // Check login
  if (page.url().includes('passport') || page.url().includes('login')) {
    console.log('需要登录，请在浏览器中手动登录...');
    await page.waitForURL(u => !u.includes('passport'), { timeout: 120000 }).catch(() => {});
  }
  console.log('当前:', page.url());
  await savePageData(page, '00_marketing_home');

  // Collect all links from sidebar navigation
  const sidebarLinks = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('a, span, li, div'))
      .map(el => ({
        text: el.textContent.trim().substring(0, 60),
        tag: el.tagName,
        class: (el.className || '').substring(0, 80),
        href: (el.href || el.getAttribute('href') || '').substring(0, 200),
        id: el.id || ''
      }))
      .filter(l => l.text.length > 0 && l.text.length < 40);
  });

  // Find 全站推广 links
  const qzLinks = sidebarLinks.filter(l =>
    l.text.includes('全站推广') ||
    l.text.includes('直通车') ||
    l.text.includes('标准推广') ||
    l.text.includes('直通车报告')
  );
  console.log('\n[2] 直通车板块链接:');
  qzLinks.forEach(l => console.log(`  ${l.text} | class=${l.class} | href=${l.href}`));

  // Click 全站推广 to see campaign list
  console.log('\n[3] 点击全站推广...');
  try {
    // Find and click the 全站推广 navigation link
    const allElements = await page.$$('a, span, li, div');
    for (const el of allElements) {
      try {
        const t = await el.textContent();
        if (t.trim() === '全站推广') {
          const tag = await el.evaluate(el => el.tagName);
          console.log(`  找到元素: ${tag}`);
          if (tag === 'A') {
            const href = await el.getAttribute('href');
            if (href) {
              await page.goto(href.startsWith('http') ? href : `https://i.alibaba.com${href}`, { waitUntil: 'domcontentloaded', timeout: 30000 });
            }
          } else {
            await el.click();
          }
          break;
        }
      } catch(e) {}
    }
  } catch(e) {
    console.log('  点击失败:', e.message);
  }

  await page.waitForTimeout(5000);
  console.log('  当前URL:', page.url());
  await savePageData(page, '01_quanzhan_list');

  // Now try to find campaign plans (日预算版, 智投版)
  console.log('\n[4] 查找推广计划...');
  const planText = await page.evaluate(() => document.body.innerText);
  console.log('页面内容预览:', planText.substring(0, 2000));

  // Save all clickable elements
  const clickables = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('a, button, [role="button"], [onclick], .clickable'))
      .map(el => ({
        text: el.textContent.trim().substring(0, 80),
        tag: el.tagName,
        href: (el.href || '').substring(0, 150),
        class: (el.className || '').substring(0, 60)
      }))
      .filter(l => l.text.length > 0 && l.text.length < 50);
  });
  console.log('可点击元素:');
  clickables.forEach(l => console.log(`  ${l.text} | ${l.tag} | ${l.class}`));

  // Look for campaign plans - click on them to see product-level data
  const planNames = ['日预算', '智投版', '日预算全站推广', '智投版全站推广'];
  for (const name of planNames) {
    for (const el of clickables) {
      if (el.text.includes(name)) {
        console.log(`\n[5] 点击 "${el.text}"...`);
        // Try to click
        // ... save data
      }
    }
  }

  // Try to find the campaign management URLs
  const allUrls = await page.evaluate(() => {
    return Array.from(document.querySelectorAll('a[href]'))
      .map(a => a.href)
      .filter(h => h.includes('campaign') || h.includes('ad.') || h.includes('promotion'));
  });
  console.log('\n推广相关URL:', [...new Set(allUrls)]);

  // Try common P4P campaign list URLs for i.alibaba.com
  console.log('\n[6] 尝试访问直通车推广计划管理页面...');
  const campaignUrls = [
    'https://crm.i.alibaba.com/ad/campaign/list',
    'https://i.alibaba.com/ads/campaign/list',
  ];
  for (const url of campaignUrls) {
    try {
      console.log(`  尝试 ${url}...`);
      await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 20000 });
      await page.waitForTimeout(3000);
      if (!page.url().includes('passport') && !page.url().includes('login') && !page.url().includes('404')) {
        console.log(`  ✓ 成功! -> ${page.url()}`);
